import React, { useState } from 'react';
import { CASE_STUDIES } from '../constants';
import { ArrowUpRight, BarChart3, CheckCircle2, Target, TrendingUp } from 'lucide-react';
import { CaseStudy } from '../types';

const CaseStudies: React.FC = () => {
  const [activeId, setActiveId] = useState<string | null>(
    (CASE_STUDIES && CASE_STUDIES.length > 0) ? CASE_STUDIES[0].id : null
  );

  const activeStudy = CASE_STUDIES.find(c => c.id === activeId);

  const getChartData = (study: CaseStudy) => {
     if (!study || !study.metrics) return [];

     return study.metrics.map(m => {
        let val = 50; 
        const s = m.value;

        if (s.includes('%')) {
            val = parseInt(s.replace(/\D/g, '')) || 0;
        } 
        else if (s.includes('$') || s.includes('M') || s.includes('k')) {
            val = 95; 
        }
        else if (s.toLowerCase().includes('real-time') || s.toLowerCase().includes('auto') || s.toLowerCase().includes('high') || s.toLowerCase().includes('dynamic')) {
            val = 90; 
        }
        else {
            const parsed = parseInt(s.replace(/\D/g, ''));
            if (!isNaN(parsed)) {
                val = parsed > 100 ? 100 : Math.max(parsed, 40);
            } else {
                val = 75; 
            }
        }

        return {
          name: m.label,
          value: Math.max(30, Math.min(val, 100)), 
          fullValue: m.value
        };
     });
  };

  const renderChart = (study: CaseStudy) => {
    const data = getChartData(study);

    return (
      <div className="flex-grow w-full flex items-end justify-around gap-4 pt-4 pb-2">
        {data.map((item, i) => (
          <div key={i} className="flex flex-col items-center justify-end h-full w-full max-w-[70px] group">
            <div className="relative w-full h-full bg-slate-800/40 rounded-xl flex items-end overflow-hidden ring-1 ring-white/5">
               <div 
                  style={{ height: `${item.value}%` }}
                  className="w-full bg-blue-500 rounded-t-lg transition-all duration-1000 ease-out group-hover:bg-blue-400 group-hover:shadow-[0_0_15px_rgba(59,130,246,0.5)]"
               >
                  <div className="absolute inset-0 bg-gradient-to-t from-black/20 to-transparent"></div>
               </div>
            </div>
            <div className="mt-3 text-center">
              <span className="block text-[8px] text-slate-500 uppercase font-black tracking-tighter mb-1">{item.name}</span>
              <span className="block text-xs font-bold text-white">{item.fullValue}</span>
            </div>
          </div>
        ))}
      </div>
    );
  };

  return (
    <section id="work" className="py-16 md:py-24 bg-white/40 dark:bg-midnight/40 transition-colors duration-300">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
