                        {activeStudy.star.task}
                      </p>
                    </div>
                  </div>

                  {/* Actions & Implementation */}
                  <div className="grid md:grid-cols-2 gap-8 items-start">
                    <div className="space-y-6">
                      <div className="flex items-center gap-3 text-blue-600 dark:text-blue-400">
                        <BarChart3 className="h-6 w-6" />
                        <h4 className="text-xl font-bold">Key Actions</h4>
                      </div>
                      <ul className="space-y-5">
                        {activeStudy.star.action.map((act, i) => (
                          <li key={i} className="flex gap-4 group">
                            <div className="mt-1.5 h-1.5 w-1.5 rounded-full bg-blue-600 shrink-0 group-hover:scale-150 transition-transform"></div>
                            <p className="text-slate-600 dark:text-slate-300 text-sm leading-relaxed">{act}</p>
                          </li>
                        ))}
                      </ul>
                    </div>

                    {/* Results Section with Dark Metrics Card */}
                    <div className="space-y-8">
                       <div className="flex items-center gap-3 text-emerald-600 dark:text-emerald-400">
                          <CheckCircle2 className="h-6 w-6" />
                          <h4 className="text-xl font-bold">Key Results</h4>
                       </div>

                       <div className="space-y-3">
                        {activeStudy.star.result.slice(0, 2).map((res, i) => (
                          <div key={i} className="p-4 bg-white dark:bg-slate-800/40 border border-slate-100 dark:border-slate-800 rounded-2xl flex gap-3 items-start">
                            <div className="h-2 w-2 rounded-full bg-emerald-500 mt-1.5 shrink-0" />
                            <p className="text-slate-600 dark:text-slate-300 text-sm font-medium">{res}</p>
                          </div>
                        ))}
                       </div>

                       {/* Impact Metrics Card - High Fidelity */}
                       <div className="bg-slate-950 rounded-3xl p-6 shadow-2xl ring-1 ring-white/10 relative overflow-hidden min-h-[220px] flex flex-col">
                          <div className="absolute top-0 right-0 w-32 h-32 bg-blue-500/10 blur-3xl rounded-full pointer-events-none"></div>
                          <p className="text-[10px] font-black text-slate-500 uppercase tracking-[0.25em] mb-4">Impact Metrics</p>
                          {renderChart(activeStudy)}
                       </div>
                    </div>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </section>
  );
};

export default CaseStudies;
